    "reports/verification/2026-06-25/workflow_mysql_result.json": "{\n  \"date\": \"2026-06-25\",\n  \"target\": \"mysql\",\n  \"status\": \"PASS\",\n  \"app\": \"Plu_Test\",\n  \"workflow_app_id\": \"1ced7307-32eb-49c3-af30-be381b206d90\",\n  \"endpoint\": \"http://localhost/v1/workflows/run\",\n  \"workflow_chain\": [\n    \"Dify Workflow\",\n    \"Tool Node\",\n    \"Provider Credential\",\n    \"db_query_extended\",\n    \"SQL Tool\",\n    \"MySQL\",\n    \"JSON Result\",\n    \"Workflow Output\"\n  ],\n  \"tool\": \"扩展数据库查询 / 只读 SQL 查询\",\n  \"sql\": \"SELECT * FROM plugin_test_users LIMIT 5\",\n  \"output_variable\": \"result = 只读 SQL 查询 / json\",\n  \"api_result_excerpt\": {\n    \"status\": \"succeeded\",\n    \"outputs\": {\n      \"result\": [\n        {\n          \"columns\": [\"id\", \"username\", \"email\", \"department\", \"salary\", \"created_at\"],\n          \"row_count\": 5,\n          \"truncated\": false\n        }\n      ]\n    },\n    \"total_steps\": 3,\n    \"error\": null\n  },\n  \"notes\": [\n    \"Tool Node was configured in Dify UI with MySQL credential.\",\n    \"Dify API returned workflow status=succeeded and non-empty outputs.result.\",\n    \"plugin-daemon logged POST /dispatch/tool/invoke status=200.\"\n  ]\n}\n",
